#!/usr/bin/env node
/**
 * Weekly seed-corpus staleness check.
 *
 * For each active source in data/seed/sources.json that has a
 * last_harvested_sha, fetches the current HEAD SHA from GitHub and compares.
 * If any sources have moved, creates or updates a single issue titled
 * "Stale harvest sources" with a summary table.
 *
 * Does NOT auto-harvest — the issue is the handoff point for a human to
 * schedule harvest sessions.
 *
 * Required: GITHUB_TOKEN and GITHUB_REPOSITORY environment variables
 * (both are set automatically in GitHub Actions).
 */

import { readFile } from 'node:fs/promises';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const WORKSPACE_ROOT = resolve(__dirname, '../..');

const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
const REPO = process.env.GITHUB_REPOSITORY;

if (!GITHUB_TOKEN) { console.error('GITHUB_TOKEN is required'); process.exit(1); }
if (!REPO) { console.error('GITHUB_REPOSITORY is required'); process.exit(1); }

const ISSUE_TITLE = 'Stale harvest sources';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function githubFetch(path, opts = {}) {
  const res = await fetch(`https://api.github.com${path}`, {
    ...opts,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
      'User-Agent': 'PromptAtrium-staleness/1',
      ...(opts.headers ?? {}),
    },
  });
  if (!res.ok) {
    const body = await res.text().catch(() => '');
    throw new Error(`GitHub API ${path}: ${res.status} ${body.slice(0, 200)}`);
  }
  return res.json();
}

async function getHeadSha(repo) {
  try {
    const data = await githubFetch(`/repos/${repo}/commits/HEAD`);
    return data.sha;
  } catch (e) {
    console.warn(`  [WARN] Could not fetch HEAD for ${repo}: ${e.message}`);
    return null;
  }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

const sourcesPath = resolve(WORKSPACE_ROOT, 'data/seed/sources.json');
const sources = JSON.parse(await readFile(sourcesPath, 'utf8'));

const stale = [];

for (const source of sources) {
  if (source.status !== 'active' || !source.last_harvested_sha) {
    // Skip wishlist, needs-human-review, and un-harvested sources
    continue;
  }

  console.log(`Checking ${source.repo}...`);
  const headSha = await getHeadSha(source.repo);
  if (!headSha) continue;

  if (headSha !== source.last_harvested_sha) {
    stale.push({
      repo: source.repo,
      kinds: source.kinds,
      harvested: source.last_harvested_sha,
      head: headSha,
    });
    console.log(`  STALE: harvested ${source.last_harvested_sha.slice(0, 8)}, now ${headSha.slice(0, 8)}`);
  } else {
    console.log(`  up to date at ${headSha.slice(0, 8)}`);
  }
}

if (stale.length === 0) {
  console.log('\nAll active sources are up to date — no issue needed.');
  process.exit(0);
}

// Build issue body
const rows = stale
  .map((s) =>
    `| \`${s.repo}\` | ${s.kinds.join(', ')} | \`${s.harvested.slice(0, 8)}\` | \`${s.head.slice(0, 8)}\` |`
  )
  .join('\n');

const issueBody = `## Stale harvest sources

The following sources have commits beyond their last-harvested SHA. Run \`/harvest-source\` on each to refresh.

| Repo | Kinds | Last harvested | Current HEAD |
|------|-------|----------------|--------------|
${rows}

**To refresh a source:**
1. Open a new Claude Code session on \`main\`
2. Invoke \`/harvest-source on <repo> [kind: <kind>]\`
3. After the PR is reviewed, merged, and audited, update \`data/seed/sources.json\` with the new \`last_harvested_sha\`
4. Close this issue once all stale sources are refreshed

*Auto-generated by seed-staleness workflow — ${new Date().toISOString().slice(0, 10)}*`;

// Find or create the issue
const allIssues = await githubFetch(`/repos/${REPO}/issues?state=open&per_page=100`);
const existing = allIssues.find((i) => i.title === ISSUE_TITLE);

if (existing) {
  await githubFetch(`/repos/${REPO}/issues/${existing.number}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ body: issueBody }),
  });
  console.log(`\nUpdated issue #${existing.number}: "${ISSUE_TITLE}"`);
} else {
  const created = await githubFetch(`/repos/${REPO}/issues`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      title: ISSUE_TITLE,
      body: issueBody,
      labels: ['harvest', 'maintenance'],
    }),
  });
  console.log(`\nCreated issue #${created.number}: "${ISSUE_TITLE}"`);
}
